    internal class PurpleMinMaxLengthCheckConverter : JsonConverter<string>
    {
        public override bool CanConvert(Type t) => t == typeof(string);

        public override string Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var value = reader.GetString();
            if (value.Length <= 256)
            {
                return value;
            }
            throw new Exception("Cannot unmarshal type string");
        }

        public override void Write(Utf8JsonWriter writer, string value, JsonSerializerOptions options)
        {
            if (value.Length <= 256)
            {
                JsonSerializer.Serialize(writer, value, options);
                return;
            }
            throw new Exception("Cannot marshal type string");
        }

        public static readonly PurpleMinMaxLengthCheckConverter Singleton = new PurpleMinMaxLengthCheckConverter();
    }

    internal class ModeConverter : JsonConverter<Mode>
    {
        public override bool CanConvert(Type t) => t == typeof(Mode);

        public override Mode Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var value = reader.GetString();
            switch (value)
            {
                case "disabled":
                    return Mode.Disabled;
                case "fast":
                    return Mode.Fast;
                case "normal":
                    return Mode.Normal;
                case "slow":
                    return Mode.Slow;
            }
            throw new Exception("Cannot unmarshal type Mode");
        }

        public override void Write(Utf8JsonWriter writer, Mode value, JsonSerializerOptions options)
        {
            switch (value)
            {
                case Mode.Disabled:
                    JsonSerializer.Serialize(writer, "disabled", options);
                    return;
                case Mode.Fast:
                    JsonSerializer.Serialize(writer, "fast", options);
                    return;
                case Mode.Normal:
                    JsonSerializer.Serialize(writer, "normal", options);
                    return;
                case Mode.Slow:
                    JsonSerializer.Serialize(writer, "slow", options);
                    return;
            }
            throw new Exception("Cannot marshal type Mode");
        }

        public static readonly ModeConverter Singleton = new ModeConverter();
    }

