    internal class TypeEnumConverter : JsonConverter<TypeEnum>
    {
        public override bool CanConvert(Type t) => t == typeof(TypeEnum);

        public override TypeEnum Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var value = reader.GetString();
            if (value == "json")
            {
                return TypeEnum.Json;
            }
            throw new Exception("Cannot unmarshal type TypeEnum");
        }

        public override void Write(Utf8JsonWriter writer, TypeEnum value, JsonSerializerOptions options)
        {
            if (value == TypeEnum.Json)
            {
                JsonSerializer.Serialize(writer, "json", options);
                return;
            }
            throw new Exception("Cannot marshal type TypeEnum");
        }

        public static readonly TypeEnumConverter Singleton = new TypeEnumConverter();
    }

    internal class VariantConverter : JsonConverter<Variant>
    {
        public override bool CanConvert(Type t) => t == typeof(Variant);

        public override Variant Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var value = reader.GetString();
            switch (value)
            {
                case "multipart":
                    return Variant.Multipart;
                case "singlepart":
                    return Variant.Singlepart;
            }
            throw new Exception("Cannot unmarshal type Variant");
        }

        public override void Write(Utf8JsonWriter writer, Variant value, JsonSerializerOptions options)
        {
            switch (value)
            {
                case Variant.Multipart:
                    JsonSerializer.Serialize(writer, "multipart", options);
                    return;
                case Variant.Singlepart:
                    JsonSerializer.Serialize(writer, "singlepart", options);
                    return;
            }
            throw new Exception("Cannot marshal type Variant");
        }

        public static readonly VariantConverter Singleton = new VariantConverter();
    }

